import UIKit
import Foundation

class StockTradeViewController: UIViewController {
    
    var portfolio: [String: Double] = [:] // Stock symbol and quantity
    let apiKey = "YOUR_API_KEY"
    let baseURL = "https://api.yourtradingplatform.com"
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    func setupUI() {
        // Setup UI elements for trading interface
    }
    
    func executeTrade(symbol: String, quantity: Double, isBuy: Bool) {
        let endpoint = isBuy ? "/buy" : "/sell"
        let url = URL(string: "\(baseURL)\(endpoint)")!
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let tradeDetails: [String: Any] = [
            "symbol": symbol,
            "quantity": quantity
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: tradeDetails, options: [])
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            guard error == nil else {
                print("Error executing trade: \(error!)")
                return
            }
            if let data = data {
                self.handleTradeResponse(data: data)
            }
        }
        task.resume()
    }
    
    func handleTradeResponse(data: Data) {
        do {
            if let json = try JSONSerialization.jsonObject(with: data, options: []) as? [String: Any],
               let success = json["success"] as? Bool {
                if success {
                    print("Trade executed successfully.")
                } else {
                    print("Trade execution failed.")
                }
            }
        } catch {
            print("Error parsing response: \(error)")
        }
    }
    
    func updatePortfolio(symbol: String, quantity: Double) {
        if let currentQuantity = portfolio[symbol] {
            portfolio[symbol] = currentQuantity + quantity
        } else {
            portfolio[symbol] = quantity
        }
    }
    
    func fetchPortfolio() {
        let url = URL(string: "\(baseURL)/portfolio")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization")
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            guard error == nil else {
                print("Error fetching portfolio: \(error!)")
                return
            }
            if let data = data {
                self.handlePortfolioResponse(data: data)
            }
        }
        task.resume()
    }
    
    func handlePortfolioResponse(data: Data) {
        do {
            if let json = try JSONSerialization.jsonObject(with: data, options: []) as? [String: Any],
               let stocks = json["stocks"] as? [[String: Any]] {
                for stock in stocks {
                    if let symbol = stock["symbol"] as? String,
                       let quantity = stock["quantity"] as? Double {
                        portfolio[symbol] = quantity
                    }
                }
                print("Portfolio updated: \(portfolio)")
            }
        } catch {
            print("Error parsing portfolio response: \(error)")
        }
    }
}